203	/// Parse a raw wildcard tail (still percent-encoded, `/`-separated) into a
204	/// structured path. `None` mirrors the live server's 404 surface for the
205	/// producer link vocabulary.
206	pub fn parse(raw: &str) -> Option<ThyPath> {
207	    let segs: Vec<String> = raw.split('/').map(decode_segment).collect();
208	    let s: Vec<&str> = segs.iter().map(String::as_str).collect();
209	    match s.as_slice() {
210	        ["help", ..] => Some(ThyPath::Help),
211	        ["message", ..] => Some(ThyPath::Message),
212	        ["rules", ..] => Some(ThyPath::Rules),
213	        ["tactic", ..] => Some(ThyPath::Tactic),
214	        ["cases", kind @ ("raw" | "refined"), i, j, ..] => Some(ThyPath::Sources {
215	            refined: *kind == "refined",
216	            source_idx: parse_numeric(i)?,
217	            case_idx: parse_numeric(j)?,
218	        }),
219	        ["lemma", name, ..] => Some(ThyPath::Lemma((*name).to_string())),
220	        ["proof", lemma, sub @ ..] => Some(ThyPath::Proof {
221	            lemma: (*lemma).to_string(),
222	            sub: sub.iter().map(|s| s.to_string()).collect(),
223	        }),
224	        ["edit", name, ..] => Some(ThyPath::Edit((*name).to_string())),
225	        ["add", pos, ..] => Some(ThyPath::Add((*pos).to_string())),
226	        ["delete", name, ..] => Some(ThyPath::Delete((*name).to_string())),
227	        _ => None,
228	    }
229	}
