231	/// Render a structured path to its href segments (percent-encoded; join with
232	/// `/` for the wildcard tail). Byte-reproduces every harvested corpus href
233	/// tail in the vocabulary ([S14], tests/r5_path_grammar.rs).
234	pub fn render(path: &ThyPath) -> Vec<String> {
235	    match path {
236	        ThyPath::Help => vec!["help".into()],
237	        ThyPath::Message => vec!["message".into()],
238	        ThyPath::Rules => vec!["rules".into()],
239	        ThyPath::Tactic => vec!["tactic".into()],
240	        ThyPath::Sources {
241	            refined,
242	            source_idx,
243	            case_idx,
244	        } => vec![
245	            "cases".into(),
246	            if *refined { "refined" } else { "raw" }.into(),
247	            source_idx.to_string(),
248	            case_idx.to_string(),
249	        ],
250	        ThyPath::Lemma(name) => vec!["lemma".into(), encode_segment(name)],
251	        ThyPath::Proof { lemma, sub } => {
252	            let mut v = vec!["proof".into(), encode_segment(lemma)];
253	            v.extend(sub.iter().map(|s| encode_segment(s)));
254	            v
255	        }
256	        ThyPath::Edit(name) => vec!["edit".into(), encode_segment(name)],
257	        ThyPath::Add(pos) => vec!["add".into(), encode_segment(pos)],
258	        ThyPath::Delete(name) => vec!["delete".into(), encode_segment(name)],
259	    }
260	}
