1	//! R2 — the proof-script WEST pane (the theory index left of every page).
2	//!
3	//! The pane is a flat document of logical lines put through the R1 per-line
4	//! postprocess (each line + `<br/>\n`, leading spaces → `&nbsp;`) with ONE
5	//! trailing space after the last break (all 473 corpus panes end `<br/>\n `
6	//! [S16]). Element order (BEHAVIOR.md §11, [S16]):
7	//!
8	//!   1. `theory NAME begin` header (NAME links to `main/help`);
9	//!   2. per nav item: a blank line, then the item link line;
10	//!   3. blank + the `add lemma` link for position `<first>`;
11	//!   4. per lemma: blank, declaration line(s), the edit-or-delete link line,
12	//!      the proof display (a `by sorry` step or the pre-rendered proof lines),
13	//!      blank, that lemma's `add lemma` link;
14	//!   5. blank + `end` — with zero lemmas the pane shows TWO blanks here
15	//!      (steps 3→5 with an empty step 4, observed in the 2 lemma-less panes).
16	//!
17	//! Every internal href is `/thy/trace/{idx}/main/` + an R5-rendered theory
18	//! path — R2 constructs its links through [`crate::path::render`].
19	//!
20	//! The lemma DECLARATION is `lemma {name}{attributes}:` (attributes text
21	//! opaque, possibly multi-line [S17]), then the quantifier/formula block at
22	//! indent 2 with the inline-vs-vertical layout rule pinned by [S18]/[L14]:
23	//! a single-line formula joins the quantifier line when the assembled line's
24	//! ESCAPED width (tags stripped, entities counted at their escaped length)
25	//! is ≤ 69 characters; otherwise the quantifier stands alone and the formula
26	//! lines follow, each at the 2-space block indent plus its own relative
27	//! indent. A proved/disproved lemma's header (declaration + edit/delete line)
28	//! is wrapped in a single status span (`hl_good` / `hl_bad`); an incomplete
29	//! proof leaves the header unwrapped [S16].
30	
31	use crate::html::{escape_text, postprocess_lines};
32	use crate::model::{LemmaEntry, ProofDisplay, ProofScriptPane, ThyPath};
33	use crate::path;
34	
35	/// The inline-layout width limit: a quantifier+formula line inlines iff its
36	/// escaped width is ≤ this. Bisected live to exactly 69/70 on all four probe
37	/// families ([L14]); the corpus straddles it at 65/71 ([S18]).
38	const INLINE_WIDTH_LIMIT: usize = 69;
39	
40	/// Escaped width of a document line: HTML tags count 0, every other character
41	/// (entities at their escaped length, unicode per char) counts 1 ([S18][L14]).
42	fn escaped_width(line: &str) -> usize {
43	    let mut w = 0;
44	    let mut in_tag = false;
45	    for c in line.chars() {
46	        match c {
47	            '<' => in_tag = true,
48	            '>' => in_tag = false,
49	            _ if !in_tag => w += 1,
50	            _ => {}
51	        }
52	    }
53	    w
54	}
55	
56	fn href(idx: u64, target: &ThyPath) -> String {
57	    format!("/thy/trace/{idx}/main/{}", path::render(target).join("/"))
58	}
59	
60	fn add_link(idx: u64, pos: &str) -> String {
61	    format!(
62	        r#"<a class="internal-link add" href="{}">add lemma</a>"#,
63	        href(idx, &ThyPath::Add(pos.to_string()))
64	    )
65	}
66	
67	fn keyword(kw: &str) -> String {
68	    format!(r#"<span class="hl_keyword">{kw}</span>"#)
69	}
70	
71	/// Push one lemma's lines (declaration, edit/delete, proof display).
72	fn push_lemma(elems: &mut Vec<String>, idx: u64, lemma: &LemmaEntry) {
73	    let name_html = escape_text(&lemma.name);
74	    let decl = format!("{} {}{}:", keyword("lemma"), name_html, lemma.attributes);
75	    let edit_delete = format!(
76	        r#"<a class="internal-link edit" href="{}">edit lemma</a>  or  <a class="internal-link delete" href="{}">delete lemma</a>"#,
77	        href(idx, &ThyPath::Edit(lemma.name.clone())),
78	        href(idx, &ThyPath::Delete(lemma.name.clone()))
79	    );
80	    // Header wrapper: one status span around declaration + edit/delete line
81	    // for a complete proof; none for `sorry` or an incomplete proof.
82	    let header_status = match &lemma.proof {
83	        ProofDisplay::Rendered { header_status, .. } => header_status.as_deref(),
84	        _ => None,
85	    };
86	    match header_status {
87	        Some(status) => {
88	            elems.push(format!(r#"<span class="{status}">{decl}"#));
89	            elems.push(format!("{edit_delete}</span>"));
90	        }
91	        None => {
92	            elems.push(decl);
93	            elems.push(edit_delete);
94	        }
95	    }
96	    // The quantifier/formula block goes BETWEEN the declaration and the
97	    // edit/delete line.
98	    let at = elems.len() - 1;
99	    let mut block: Vec<String> = Vec::new();
100	    if let [only_line] = lemma.formula.lines.as_slice() {
101	        let candidate = format!("  {} {}", lemma.quantifier, only_line);
102	        if escaped_width(&candidate) <= INLINE_WIDTH_LIMIT {
103	            block.push(candidate);
104	        }
105	    }
106	    if block.is_empty() {
107	        block.push(format!("  {}", lemma.quantifier));
108	        for line in &lemma.formula.lines {
109	            block.push(format!("  {line}"));
110	        }
111	    }
112	    elems.splice(at..at, block);
113	    // Proof display.
114	    match &lemma.proof {
115	        ProofDisplay::Unproven => elems.push(format!(
116	            r#"{} <a class="internal-link proof-step sorry-step" href="{}">{}</a>"#,
117	            keyword("by"),
118	            href(idx, &ThyPath::Proof { lemma: lemma.name.clone(), sub: vec![] }),
119	            keyword("sorry")
120	        )),
121	        ProofDisplay::Rendered { lines, .. } => elems.extend(lines.iter().cloned()),
122	        ProofDisplay::Tree(_) => unimplemented!("R3: structured proof-tree rendering"),
123	    }
124	}
125	
126	/// Render the inner HTML of the west proof-script pane (the content of the
127	/// page's proof-script container, final trailing space included).
128	pub fn render_index(pane: &ProofScriptPane) -> String {
129	    let idx = pane.index;
130	    let mut elems: Vec<String> = Vec::new();
131	    elems.push(format!(
132	        r#"{} <a class="internal-link help" href="{}">{}</a> {}"#,
133	        keyword("theory"),
134	        href(idx, &ThyPath::Help),
135	        escape_text(&pane.theory_name),
136	        keyword("begin")
137	    ));
138	    for item in &pane.items {
139	        elems.push(String::new());
140	        elems.push(format!(
141	            r#"<a class="internal-link" href="{}"><strong>{}</strong> {}</a>"#,
142	            href(idx, &item.target),
143	            item.label,
144	            item.annotation
145	        ));
146	    }
147	    elems.push(String::new());
148	    elems.push(add_link(idx, "<first>"));
149	    if pane.lemmas.is_empty() {
150	        // A lemma-less pane leaves TWO blank lines before `end` (both
151	        // lemma-less corpus panes [S16]).
152	        elems.push(String::new());
153	    }
154	    for lemma in &pane.lemmas {
155	        elems.push(String::new());
156	        push_lemma(&mut elems, idx, lemma);
157	        elems.push(String::new());
158	        elems.push(add_link(idx, &lemma.name));
159	    }
160	    elems.push(String::new());
161	    elems.push(keyword("end"));
162	    let mut out = postprocess_lines(&elems.join("\n"));
163	    out.push(' ');
164	    out
165	}
