1	//! R2 acceptance — the proof-script WEST pane assembly.
2	//!
3	//! For every overview capture across the 81 manifests (478 bodies: 396 proof
4	//! views + 82 help views, materialized by tools/extract_r2_panes.py into
5	//! workspace/r2_panes/), this test:
6	//!   1. reads the pane inner HTML (the proof-script container's content);
7	//!   2. INVERTS the producer's skin — un-postprocessing into logical lines and
8	//!      slicing the opaque content (item labels/annotations, lemma names,
9	//!      attribute text, formula lines, proof-display lines) out of the strict
10	//!      observed skeleton, with every frame byte asserted on the way;
11	//!   3. feeds the slices back through `render_proof_script` and asserts the
12	//!      re-rendered pane equals the captured bytes EXACTLY.
13	//!
14	//! A second test replays live-captured panes from theories NOT in the corpus
15	//! (workspace/r2_live/, QUERIES.log [L15]) including a proved state, pinning
16	//! the inline-layout width boundary at exactly 69/70 ([L14]).
17	//!
18	//! The inversion is intentionally strict (panics on any unexpected shape) so
19	//! a capture deviating from the modeled skeleton fails loudly.
20	
21	use std::fs;
22	use std::path::PathBuf;
23	
24	use producers_clean::model::{
25	    Content, LemmaEntry, NavItem, ProofDisplay, ProofScriptPane, ThyPath,
26	};
27	use producers_clean::{parse_path, render_proof_script};
28	
29	fn workspace_path(rel: &str) -> PathBuf {
30	    PathBuf::from(env!("CARGO_MANIFEST_DIR")).join(rel)
31	}
32	
33	// ---------------------------------------------------------------------------
34	// Line-level inversion helpers
35	// ---------------------------------------------------------------------------
36	
37	/// Invert the per-line postprocess: split on `<br/>\n`, leading `&nbsp;` runs
38	/// back to spaces; assert the pane's final ` ` frame byte.
39	fn pane_lines(inner: &str) -> Vec<String> {
40	    let doc = inner
41	        .strip_suffix(' ')
42	        .expect("pane ends with the trailing space");
43	    assert!(doc.ends_with("<br/>\n"), "pane lines end with breaks");
44	    let mut lines: Vec<&str> = doc.split("<br/>\n").collect();
45	    assert_eq!(lines.pop(), Some(""), "trailing separator");
46	    lines
47	        .iter()
48	        .map(|line| {
49	            let mut rest = *line;
50	            let mut n = 0;
51	            while let Some(r) = rest.strip_prefix("&nbsp;") {
52	                rest = r;
53	                n += 1;
54	            }
55	            format!("{}{}", " ".repeat(n), rest)
56	        })
57	        .collect()
58	}
59	
60	/// Reverse of the producer's entity escape (strict).
61	fn unescape_entities(s: &str) -> String {
62	    let mut out = String::with_capacity(s.len());
63	    let mut rest = s;
64	    while let Some(i) = rest.find('&') {
65	        out.push_str(&rest[..i]);
66	        rest = &rest[i..];
67	        let (c, len) = if rest.starts_with("&amp;") {
68	            ('&', 5)
69	        } else if rest.starts_with("&lt;") {
70	            ('<', 4)
71	        } else if rest.starts_with("&gt;") {
72	            ('>', 4)
73	        } else if rest.starts_with("&quot;") {
74	            ('"', 6)
75	        } else if rest.starts_with("&#39;") {
76	            ('\'', 5)
77	        } else {
78	            panic!("unknown entity at {:?}", &rest[..rest.len().min(8)]);
79	        };
80	        out.push(c);
81	        rest = &rest[len..];
82	    }
83	    out.push_str(rest);
84	    out
85	}
