87	/// Escaped width as the layout rule measures it (tags 0, all else 1/char).
88	fn escaped_width(line: &str) -> usize {
89	    let mut w = 0;
90	    let mut in_tag = false;
91	    for c in line.chars() {
92	        match c {
93	            '<' => in_tag = true,
94	            '>' => in_tag = false,
95	            _ if !in_tag => w += 1,
96	            _ => {}
97	        }
98	    }
99	    w
100	}
