109	fn slice_pane(inner: &str) -> (u64, ProofScriptPane) {
110	    let lines = pane_lines(inner);
111	    let mut i = 0;
112	
113	    // 1. Header line.
114	    let rest = lines[0]
115	        .strip_prefix("<span class=\"hl_keyword\">theory</span> <a class=\"internal-link help\" href=\"/thy/trace/")
116	        .expect("theory header line");
117	    let (idx_str, rest) = rest.split_once("/main/help\">").expect("help href");
118	    let idx: u64 = idx_str.parse().expect("numeric index");
119	    let name = rest
120	        .strip_suffix("</a> <span class=\"hl_keyword\">begin</span>")
121	        .expect("begin keyword");
122	    let theory_name = unescape_entities(name);
123	    i += 1;
124	
125	    // 2. Item link lines (blank + item), until the add-first link.
126	    let mut items = Vec::new();
127	    loop {
128	        assert_eq!(lines[i], "", "blank before item/add line");
129	        if lines[i + 1].starts_with("<a class=\"internal-link add\"") {
130	            break;
131	        }
132	        let it = lines[i + 1]
133	            .strip_prefix(&format!("<a class=\"internal-link\" href=\"/thy/trace/{idx}/main/"))
134	            .unwrap_or_else(|| panic!("item line shape: {:?}", lines[i + 1]));
135	        let (tail, it) = it.split_once("\"><strong>").expect("item strong open");
136	        let (label, it) = it.split_once("</strong> ").expect("item strong close");
137	        let annotation = it.strip_suffix("</a>").expect("item anchor close");
138	        let target = parse_path(tail).expect("item target parses");
139	        // The link is canonical: R5 re-renders it byte-identically.
140	        items.push(NavItem {
141	            target,
142	            label: label.to_string(),
143	            annotation: annotation.to_string(),
144	        });
145	        i += 2;
146	    }
147	    // 3. The add-first link.
148	    assert_eq!(
149	        lines[i + 1],
150	        format!("<a class=\"internal-link add\" href=\"/thy/trace/{idx}/main/add/%3Cfirst%3E\">add lemma</a>"),
151	        "add-first link"
152	    );
153	    i += 2;
154	
155	    // 4. Lemma blocks; 5. end.
156	    let mut lemmas = Vec::new();
157	    loop {
158	        assert_eq!(lines[i], "", "blank before lemma/end");
159	        i += 1;
160	        if lines[i] == KW_END {
161	            assert_eq!(i, lines.len() - 1, "end is the last line");
162	            break;
163	        }
164	        if lines[i].is_empty() && lines[i + 1] == KW_END {
165	            // Zero-lemma pane: two blanks before `end`.
166	            assert!(lemmas.is_empty());
167	            assert_eq!(i + 1, lines.len() - 1, "end is the last line");
168	            break;
169	        }
170	
171	        // 4a. Declaration line(s), with optional status wrapper.
172	        let (wrapper, decl_rest) = match lines[i].strip_prefix(KW_LEMMA) {
173	            Some(rest) => (None, rest.to_string()),
174	            None => {
175	                let w = lines[i]
176	                    .strip_prefix("<span class=\"")
177	                    .unwrap_or_else(|| panic!("decl line shape: {:?}", lines[i]));
178	                let (class, rest) = w.split_once("\">").expect("wrapper span open");
179	                let rest = rest.strip_prefix(KW_LEMMA).expect("lemma keyword after wrapper");
180	                (Some(class.to_string()), rest.to_string())
181	            }
182	        };
183	        let mut decl = decl_rest;
184	        while !decl.ends_with(':') {
185	            i += 1;
186	            decl.push('\n');
187	            decl.push_str(&lines[i]);
188	        }
189	        i += 1;
190	        let decl = decl.strip_suffix(':').unwrap();
191	        let (name_html, attributes) = match decl.find(" [") {
192	            Some(p) => (&decl[..p], &decl[p..]),
193	            None => (decl, ""),
194	        };
195	        let name = unescape_entities(name_html);
196	
197	        // 4b. Quantifier / formula block at indent 2.
198	        let q = lines[i]
199	            .strip_prefix("  ")
200	            .unwrap_or_else(|| panic!("quantifier indent: {:?}", lines[i]));
201	        let (quantifier, formula_lines) = if let Some((kw, rest)) = q.split_once(' ') {
202	            assert!(matches!(kw, "all-traces" | "exists-trace"), "quantifier {kw:?}");
203	            // Inline layout: the assembled line obeys the width limit.
204	            assert!(
205	                escaped_width(&lines[i]) <= 69,
206	                "inline line wider than 69: {:?}",
207	                lines[i]
208	            );
209	            i += 1;
210	            (kw.to_string(), vec![rest.to_string()])
211	        } else {
212	            assert!(matches!(q, "all-traces" | "exists-trace"), "quantifier {q:?}");
213	            let kw = q.to_string();
214	            i += 1;
215	            let mut fl = Vec::new();
216	            while !lines[i].starts_with("<a class=\"internal-link edit\"") {
217	                let l = lines[i]
218	                    .strip_prefix("  ")
219	                    .unwrap_or_else(|| panic!("formula indent: {:?}", lines[i]));
220	                fl.push(l.to_string());
221	                i += 1;
222	            }
223	            // Vertical layout is justified: multi-line, or over the limit.
224	            if let [only] = fl.as_slice() {
225	                assert!(
226	                    escaped_width(&format!("  {kw} {only}")) > 69,
227	                    "single-line formula under the limit rendered vertically"
228	                );
229	            }
230	            (kw, fl)
231	        };
232	
233	        // 4c. Edit-or-delete line (closes the wrapper span when present).
234	        let e = lines[i]
235	            .strip_prefix(&format!("<a class=\"internal-link edit\" href=\"/thy/trace/{idx}/main/edit/"))
236	            .unwrap_or_else(|| panic!("edit line shape: {:?}", lines[i]));
237	        let (enc_name, e) = e.split_once("\">edit lemma</a>  or  ").expect("or separator");
238	        let e = e
239	            .strip_prefix(&format!("<a class=\"internal-link delete\" href=\"/thy/trace/{idx}/main/delete/"))
240	            .expect("delete anchor");
241	        let (_enc2, e) = e.split_once("\">delete lemma</a>").expect("delete anchor close");
242	        match wrapper {
243	            Some(_) => assert_eq!(e, "</span>", "wrapper closes after delete anchor"),
244	            None => assert_eq!(e, "", "no wrapper close on a bare header"),
245	        }
246	        i += 1;
247	
248	        // 4d. Proof display: the exact sorry step, or opaque pre-rendered lines.
249	        let sorry_line = format!(
250	            "<span class=\"hl_keyword\">by</span> <a class=\"internal-link proof-step sorry-step\" href=\"/thy/trace/{idx}/main/proof/{enc_name}\"><span class=\"hl_keyword\">sorry</span></a>"
251	        );
252	        let proof = if lines[i] == sorry_line {
253	            assert!(wrapper.is_none(), "sorry proof has no header wrapper");
254	            i += 1;
255	            ProofDisplay::Unproven
256	        } else {
257	            let mut pl = Vec::new();
258	            while !lines[i].is_empty() {
259	                pl.push(lines[i].clone());
260	                i += 1;
261	            }
262	            ProofDisplay::Rendered {
263	                header_status: wrapper,
264	                lines: pl,
265	            }
266	        };
267	
268	        // 4e. Blank + this lemma's add link.
269	        assert_eq!(lines[i], "", "blank after proof display");
270	        assert_eq!(
271	            lines[i + 1],
272	            format!("<a class=\"internal-link add\" href=\"/thy/trace/{idx}/main/add/{enc_name}\">add lemma</a>"),
273	            "per-lemma add link"
274	        );
275	        i += 2;
276	
277	        lemmas.push(LemmaEntry {
278	            name,
279	            attributes: attributes.to_string(),
280	            quantifier,
281	            formula: Content { lines: formula_lines },
282	            proof,
283	        });
284	    }
285	
286	    (
287	        idx,
288	        ProofScriptPane {
289	            theory_name,
290	            index: idx,
291	            items,
292	            lemmas,
293	        },
294	    )
295	}
