297	fn replay(inner: &str) -> String {
298	    let (_idx, pane) = slice_pane(inner);
299	    // Structural expectations that hold corpus-wide ([S16]): five nav items,
300	    // message first, both sources views present.
301	    assert_eq!(pane.items.len(), 5, "five nav items");
302	    assert_eq!(pane.items[0].target, ThyPath::Message);
303	    render_proof_script(&pane)
304	}
